Certainly! Below is a **`minigit`** implementation in JavaScript (Node.js) according to what’s usually required by **SPEC-v1.txt** for a minimal VCS (like git). This assumes:

- All required commands: `init`, `add`, `commit`, `status`, `log`, etc.
- Tracking files in a `.minigit` directory.
- Only plain text files, no branching/merging, no remote.

### 1. `minigit` Executable

Create a file named `minigit`:

```javascript
#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const MG_DIR = '.minigit';

// Utility: SHA1 hash of content
function sha1(data) {
    return crypto.createHash('sha1').update(data).digest('hex');
}

// Utility: Ensure directory exists
function ensureDir(dir) {
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

// Paths
const paths = {
    mg: MG_DIR,
    objects: MG_DIR + '/objects',
    index: MG_DIR + '/index',
    head: MG_DIR + '/HEAD',
    log: MG_DIR + '/log'
};

function mgInit() {
    if (fs.existsSync(MG_DIR)) {
        console.log('Repository already initialized.');
        return;
    }
    ensureDir(paths.mg);
    ensureDir(paths.objects);
    fs.writeFileSync(paths.index, '{}\n');
    fs.writeFileSync(paths.head, '');
    fs.writeFileSync(paths.log, '');
    console.log('Initialized empty minigit repository in ./' + paths.mg);
}

function mgAdd(filename) {
    if (!fs.existsSync(filename)) {
        console.error(`fatal: pathspec '${filename}' did not match any files`);
        process.exit(1);
    }
    let index = {};
    if (fs.existsSync(paths.index)) {
        index = JSON.parse(fs.readFileSync(paths.index));
    }
    index[filename] = sha1(fs.readFileSync(filename));
    fs.writeFileSync(paths.index, JSON.stringify(index, null, 2));
    console.log(`added '${filename}'`);
}

function mgCommit(msg) {
    if (!msg) {
        console.error('Aborting commit due to empty commit message.');
        process.exit(1);
    }
    if (!fs.existsSync(paths.index)) return;
    let index = JSON.parse(fs.readFileSync(paths.index));
    if (!Object.keys(index).length) {
        console.log('nothing to commit');
        return;
    }
    // Save blobs and build commit object
    let tree = {};
    for (let fname in index) {
        let hash = sha1(fs.readFileSync(fname));
        tree[fname] = hash;
        const obj = paths.objects + '/' + hash;
        if (!fs.existsSync(obj)) {
            fs.writeFileSync(obj, fs.readFileSync(fname));
        }
    }
    // Previous commit
    let prev = '';
    if (fs.existsSync(paths.head)) {
        prev = fs.readFileSync(paths.head, 'utf8').trim();
    }
    // Commit object
    let commit = {
        prev,
        tree,
        msg,
        timestamp: Date.now()
    };
    let commitStr = JSON.stringify(commit);
    let commitHash = sha1(commitStr);
    fs.writeFileSync(paths.objects + '/' + commitHash, commitStr);
    fs.writeFileSync(paths.head, commitHash);
    fs.appendFileSync(paths.log, commitHash + ' ' + msg + '\n');
    fs.writeFileSync(paths.index, '{}\n');
    console.log(`[${commitHash.slice(0,7)}] ${msg}`);
}

function mgStatus() {
    let index = {};
    if (fs.existsSync(paths.index)) {
        index = JSON.parse(fs.readFileSync(paths.index));
    }
    let staged = Object.keys(index);
    if (!staged.length)
        console.log('No files staged for commit');
    else {
        console.log('Staged files:');
        staged.forEach(f => {
            console.log('  ' + f);
        });
    }
}

function mgLog() {
    if (!fs.existsSync(paths.log)) {
        console.log('no commits yet');
        return;
    }
    let lines = fs.readFileSync(paths.log, 'utf8').trim().split('\n').reverse();
    for (let l of lines) {
        if (!l.trim()) continue;
        let sp = l.indexOf(' ');
        let hash = l.slice(0, sp);
        let msg = l.slice(sp + 1);
        console.log(`commit ${hash}\n    ${msg}\n`);
    }
}

function usage() {
    console.log(`usage: minigit <command> [args]

commands:
  init              Initialize repo
  add <file>        Add file to index
  commit -m "msg"   Commit staged files
  status            Show staged files
  log               Show commit log
`);
    process.exit(1);
}

function main() {
    const args = process.argv.slice(2);
    if (args.length < 1) return usage();

    switch (args[0]) {
        case 'init':
            mgInit();
            break;
        case 'add':
            if (!args[1]) usage();
            mgAdd(args[1]);
            break;
        case 'commit':
            let msg = '';
            if (args[1] === '-m' && args[2]) msg = args[2];
            mgCommit(msg);
            break;
        case 'status':
            mgStatus();
            break;
        case 'log':
            mgLog();
            break;
        default:
            usage();
    }
}

main();
```

